 34	  const { t } = useKialiTranslation();
 35	
 36	  const renderSystemErrorBadge = (): React.ReactNode => {
 37	    if (props.systemErrorsCount === 0) {
 38	      return null;
 39	    }
 40	
 41	    return (
 42	      <Button
 43	        id={'icon_warning'}
 44	        aria-label={t('System Error')}
