 91	const mapStateToPropsMessageCenterTrigger = (state: KialiAppState): ReduxStateProps => {
 92	  type MessageCenterTriggerPropsToMap = {
 93	    badgeDanger: boolean;
 94	    newMessagesCount: number;
 95	    systemErrorsCount: number;
 96	  };
 97	
 98	  const dangerousMessageTypes = [MessageType.ERROR, MessageType.WARNING];
 99	  let systemErrorsCount = 0;
100	
101	  const systemErrorsGroup = state.messageCenter.groups.find(item => item.id === 'systemErrors');
102	  if (systemErrorsGroup) {
103	    systemErrorsCount = systemErrorsGroup.messages.length;
104	  }
105	
106	  return state.messageCenter.groups
107	    .reduce((unreadMessages: NotificationMessage[], group: NotificationGroup) => {
108	      return unreadMessages.concat(
109	        group.messages.reduce((unreadMessagesInGroup: NotificationMessage[], message: NotificationMessage) => {
110	          if (!message.seen) {
111	            unreadMessagesInGroup.push(message);
112	          }
113	          return unreadMessagesInGroup;
114	        }, [])
115	      );
116	    }, [])
117	    .reduce(
118	      (propsToMap: MessageCenterTriggerPropsToMap, message: NotificationMessage) => {
119	        propsToMap.newMessagesCount++;
120	        propsToMap.badgeDanger = propsToMap.badgeDanger || dangerousMessageTypes.includes(message.type);
121	        return propsToMap;
122	      },
123	      { newMessagesCount: 0, systemErrorsCount: systemErrorsCount, badgeDanger: false }
124	    );
125	};
126	
127	const mapDispatchToPropsMessageCenterTrigger = (dispatch: KialiDispatch): ReduxDispatchProps => {
128	  return {
129	    toggleMessageCenter: () => dispatch(MessageCenterThunkActions.toggleMessageCenter()),
130	    toggleSystemErrorsCenter: () => dispatch(MessageCenterThunkActions.toggleSystemErrorsCenter())
131	  };
132	};
133	
134	export const MessageCenterTrigger = connect(
135	  mapStateToPropsMessageCenterTrigger,
136	  mapDispatchToPropsMessageCenterTrigger
137	)(MessageCenterTriggerComponent);

